-- ===========================================================
-- ROCHA FIRME MODA — script de configuração do banco de dados
--
-- COMO USAR (uma vez só):
-- 1. Crie um projeto grátis em https://supabase.com
-- 2. No menu lateral, abra "SQL Editor"
-- 3. Clique em "New query", cole TODO este arquivo, e clique em "Run"
-- 4. Pronto — a tabela é criada já com os 71 produtos do site.
--
-- Depois disso você NUNCA MAIS precisa mexer em SQL. Todo o dia a dia
-- (adicionar, editar, remover produto) é feito pela tela em admin.html.
-- ===========================================================

create table if not exists produtos (
  id          bigint generated by default as identity primary key,
  categoria   text not null,
  nome        text not null,
  slug        text not null unique,
  foto        text,
  preco       numeric(10,2) not null default 0,
  tamanhos    text not null default '',
  cores       text not null default '',
  novo        boolean not null default false,
  descricao   text not null default '',
  ativo       boolean not null default true,
  criado_em   timestamptz not null default now()
);

-- liga a segurança da tabela
alter table produtos enable row level security;

-- qualquer pessoa (o site) pode LER os produtos
drop policy if exists "Leitura publica" on produtos;
create policy "Leitura publica" on produtos
  for select using (true);

-- só quem estiver logado (a lojista, pelo admin.html) pode
-- adicionar, editar ou remover produtos
drop policy if exists "Escrita autenticada" on produtos;
create policy "Escrita autenticada" on produtos
  for all to authenticated using (true) with check (true);

-- apaga produtos de execuções anteriores deste script, pra poder rodar de novo sem duplicar
delete from produtos;

-- os 71 produtos que já existem no site (ponto de partida)
